function solve(n: number): string {
    const n2 = n * n;
    const n3 = n * n * n;

    const hexDigits = '0123456789ABCDEF';
    const hexParts: string[] = [];
    let num = n2;
    if (num === 0) {
        hexParts.push('0');
    } else {
        while (num > 0) {
            const remainder = num % 16;
            hexParts.unshift(hexDigits[remainder]);
            num = Math.floor(num / 16);
        }
    }
    const hexStr = hexParts.join('');

    const base36Digits = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    const base36Parts: string[] = [];
    num = n3;
    if (num === 0) {
        base36Parts.push('0');
    } else {
        while (num > 0) {
            const remainder = num % 36;
            base36Parts.unshift(base36Digits[remainder]);
            num = Math.floor(num / 36);
        }
    }
    const base36Str = base36Parts.join('');

    return hexStr + base36Str;
}
