function solve(n: number): string {
    const n2 = n * n;
    const n3 = n * n * n;

    const hexChars = '0123456789ABCDEF';
    const hexDigits: string[] = [];
    let num = n2;
    if (num === 0) {
        hexDigits.push('0');
    } else {
        while (num > 0) {
            const digit = num % 16;
            hexDigits.push(hexChars[digit]);
            num = Math.floor(num / 16);
        }
    }
    const hexStr = hexDigits.reverse().join('');

    const base36Chars = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    const base36Digits: string[] = [];
    num = n3;
    if (num === 0) {
        base36Digits.push('0');
    } else {
        while (num > 0) {
            const digit = num % 36;
            base36Digits.push(base36Chars[digit]);
            num = Math.floor(num / 36);
        }
    }
    const base36Str = base36Digits.reverse().join('');

    return hexStr + base36Str;
}
